export function BookingRequestPage() {
  const { user, isAuthenticated } = useAuth()
  const [searchParams] = useSearchParams()
  const queryClient = useQueryClient()
  const [form, setForm] = useState({
    tutor_id: searchParams.get('tutor') || '',
    subject_id: '',
    start_datetime: '',
    end_datetime: '',
    mode: 'ONLINE',
    notes: '',
  })
  const [notice, setNotice] = useState('')

  const tutorsQuery = useQuery({
    queryKey: ['booking-tutors'],
    queryFn: async () => (await listTutors()).data,
    enabled: true,
  })

  const subjectsQuery = useQuery({
    queryKey: ['booking-subjects'],
    queryFn: async () => (await listSubjects()).data,
    enabled: isAuthenticated,
  })

  const bookingMutation = useMutation({
    mutationFn: async () => (await createBooking({
      tutor_id: Number(form.tutor_id),
      subject_id: Number(form.subject_id),
      start_datetime: form.start_datetime,
      end_datetime: form.end_datetime,
      mode: form.mode,
      notes: form.notes,
    })).data,
    onSuccess: async () => {
      setNotice('Booking request submitted successfully.')
      setForm((current) => ({ ...current, subject_id: '', start_datetime: '', end_datetime: '', notes: '' }))
      await queryClient.invalidateQueries({ queryKey: ['booking-list'] })
    },
  })

  const tutors = normalizeTutorListResponse(tutorsQuery.data)
  const selectedTutor = tutors.find((tutor) => String(tutor.id) === String(form.tutor_id)) || null
  const subjects = Array.isArray(subjectsQuery.data) ? subjectsQuery.data : []

  if (!isAuthenticated) {
    return (
      <section className="page-card card">
        <p className="eyebrow">Request tutor</p>
        <h1>Sign in to request a booking.</h1>
        <p className="supporting-text">Students and parents can create bookings after authentication.</p>
        <div className="hero-actions">
          <Link className="primary-button" to="/sign-in">Sign in</Link>
          <Link className="secondary-button" to="/join">Create account</Link>
        </div>
      </section>
    )
  }

  if (user?.role === 'TUTOR' || user?.role === 'ADMIN') {
    return (
      <section className="page-card card">
        <p className="eyebrow">Request tutor</p>
        <h1>Booking requests are for students and parents.</h1>
        <div className="hero-actions">
          <Link className="primary-button" to="/tutors">Browse tutors</Link>
          <Link className="secondary-button" to="/contact">Contact support</Link>
        </div>
      </section>
    )
  }

  return (
    <>
      <section className="page-card card">
        <p className="eyebrow">Request tutor</p>
        <h1>Send a booking request in a few steps.</h1>
        <p className="supporting-text">Choose the tutor, the subject, and the time you need.</p>
        {notice ? <p className="supporting-text">{notice}</p> : null}
      </section>

      <section className="split-layout">
        <article className="panel card">
          <p className="eyebrow">Booking form</p>
          <h2>Create a request.</h2>
          <form className="steps-list" onSubmit={(event) => {
            event.preventDefault()
            bookingMutation.mutate()
          }}>
            <select value={form.tutor_id} onChange={(event) => setForm((current) => ({ ...current, tutor_id: event.target.value }))}>
              <option value="">Choose tutor</option>
              {tutors.map((tutor) => (
                <option key={tutor.id} value={tutor.id}>{tutor.full_name}</option>
              ))}
            </select>
            <select value={form.subject_id} onChange={(event) => setForm((current) => ({ ...current, subject_id: event.target.value }))}>
              <option value="">Choose subject</option>
              {subjects.map((subject) => (
                <option key={subject.id} value={subject.id}>{subject.name}</option>
              ))}
            </select>
            <select value={form.mode} onChange={(event) => setForm((current) => ({ ...current, mode: event.target.value }))}>
              <option value="ONLINE">Online</option>
              <option value="IN_PERSON">In person</option>
            </select>
            <input type="datetime-local" value={form.start_datetime} onChange={(event) => setForm((current) => ({ ...current, start_datetime: event.target.value }))} />
            <input type="datetime-local" value={form.end_datetime} onChange={(event) => setForm((current) => ({ ...current, end_datetime: event.target.value }))} />
            <textarea rows="4" placeholder="Notes" value={form.notes} onChange={(event) => setForm((current) => ({ ...current, notes: event.target.value }))} />
            <button className="primary-button" type="submit" disabled={bookingMutation.isPending}>Submit request</button>
          </form>
        </article>

        <article className="panel card">
          <p className="eyebrow">Selected tutor</p>
          <h2>{selectedTutor ? selectedTutor.full_name : 'Choose a tutor to continue'}</h2>
          {selectedTutor ? (
            <div className="mini-list">
              <div><span>{selectedTutor.headline || 'Tutor profile'}</span></div>
              <div><span>{selectedTutor.location || 'Online'}</span></div>
              <div><span>{formatTutorRate(selectedTutor.hourly_rate, selectedTutor.currency)}</span></div>
            </div>
          ) : (
            <p className="supporting-text">The tutor card search page can pass a tutor automatically.</p>
          )}
        </article>
      </section>
    </>
  )
}

export function BookingsPage() {
  const { user, isAuthenticated } = useAuth()
  const queryClient = useQueryClient()
  const [notice, setNotice] = useState('')

  const bookingsQuery = useQuery({
    queryKey: ['bookings'],
    queryFn: async () => (await listBookings()).data,
    enabled: isAuthenticated,
  })

  const actionMutation = useMutation({
    mutationFn: async ({ id, action }) => (await updateBookingAction(id, { action })).data,
    onSuccess: async () => {
      setNotice('Booking updated successfully.')
      await queryClient.invalidateQueries({ queryKey: ['bookings'] })
    },
  })

  const bookings = Array.isArray(bookingsQuery.data) ? bookingsQuery.data : []

  if (!isAuthenticated) {
    return (
      <section className="page-card card">
        <p className="eyebrow">Bookings</p>
        <h1>Sign in to view your bookings.</h1>
        <div className="hero-actions">
          <Link className="primary-button" to="/sign-in">Sign in</Link>
          <Link className="secondary-button" to="/join">Create account</Link>
        </div>
      </section>
    )
  }

  return (
    <>
      <section className="page-card card">
        <p className="eyebrow">Bookings</p>
        <h1>Your requests and session status.</h1>
        <p className="supporting-text">Track booking requests, confirmations, and completed sessions in one place.</p>
        {notice ? <p className="supporting-text">{notice}</p> : null}
      </section>

      <section className="card trust-section">
        <div className="section-heading section-heading-center">
          <div>
            <p className="eyebrow">Summary</p>
            <h2>{bookingsQuery.isLoading ? 'Loading bookings...' : `${bookings.length} booking${bookings.length === 1 ? '' : 's'}`}</h2>
          </div>
          <p className="section-text section-text-center">Bookings are shown for your role and linked records.</p>
        </div>
      </section>

      <section className="cards-grid">
        {bookingsQuery.isLoading ? (
          Array.from({ length: 3 }).map((_, index) => (
            <article className="tutor-card tutor-card-skeleton" key={index} aria-busy="true">
              <div className="skeleton skeleton-line skeleton-title" />
              <div className="skeleton skeleton-line" />
              <div className="skeleton skeleton-line" />
              <div className="skeleton skeleton-line skeleton-button" />
            </article>
          ))
        ) : bookings.length === 0 ? (
          <article className="panel card">
            <p className="supporting-text">No bookings yet.</p>
          </article>
        ) : (
          bookings.map((booking) => {
            const isTutor = user?.role === 'TUTOR'
            const canAct = isTutor && booking.status === 'PENDING'
            const canComplete = isTutor && booking.status === 'CONFIRMED'

            return (
              <article className="tutor-card" key={booking.id}>
                <div className="tutor-card-top">
                  <div>
                    <h3>Booking #{booking.id}</h3>
                    <p>{booking.mode} Ã‚Â· {booking.subject || 'Subject'} </p>
                  </div>
                  <span className="soft-chip">{booking.status}</span>
                </div>
                <p className="tutor-price">
                  {booking.start_datetime} to {booking.end_datetime}
                </p>
                <div className="mini-list">
                  <div><span>Total: {booking.total_amount ?? 'N/A'} {booking.currency || ''}</span></div>
                  <div><span>Rate: {booking.hourly_rate ?? 'N/A'} {booking.currency || ''}</span></div>
                </div>
                <div className="hero-actions" style={{ marginTop: 0 }}>
                  <Link className="secondary-button" to="/book">New request</Link>
                  {canAct ? (
                    <button className="primary-button" type="button" onClick={() => actionMutation.mutate({ id: booking.id, action: 'ACCEPT' })} disabled={actionMutation.isPending}>
                      Accept
                    </button>
                  ) : null}
                  {canAct ? (
                    <button className="secondary-button" type="button" onClick={() => actionMutation.mutate({ id: booking.id, action: 'REJECT' })} disabled={actionMutation.isPending}>
                      Reject
                    </button>
                  ) : null}
                  {canComplete ? (
                    <button className="primary-button" type="button" onClick={() => actionMutation.mutate({ id: booking.id, action: 'COMPLETE' })} disabled={actionMutation.isPending}>
                      Complete
                    </button>
                  ) : null}
                  {!isTutor && booking.status !== 'COMPLETED' && booking.status !== 'CANCELLED' ? (
                    <button className="secondary-button" type="button" onClick={() => actionMutation.mutate({ id: booking.id, action: 'CANCEL' })} disabled={actionMutation.isPending}>
                      Cancel
                    </button>
                  ) : null}
                </div>
              </article>
            )
          })
        )}
      </section>
    </>
  )
}

export function AdminTutorReviewsPage() {
  const { user, isAuthenticated } = useAuth()
  const queryClient = useQueryClient()
  const [reasonById, setReasonById] = useState({})
  const [notice, setNotice] = useState('')

  const verificationsQuery = useQuery({
    queryKey: ['admin-tutor-verifications'],
    queryFn: async () => (await listTutorVerifications({ status: 'PENDING' })).data,
    enabled: isAuthenticated && user?.role === 'ADMIN',
  })

  const decisionMutation = useMutation({
    mutationFn: async ({ id, status, reason }) => (await decideTutorVerification(id, { status, reason })).data,
    onSuccess: async () => {
      setNotice('Tutor verification updated successfully.')
      await queryClient.invalidateQueries({ queryKey: ['admin-tutor-verifications'] })
      await queryClient.invalidateQueries({ queryKey: ['tutors'] })
      await queryClient.invalidateQueries({ queryKey: ['tutor-dashboard'] })
      await queryClient.invalidateQueries({ queryKey: ['tutor-checklist'] })
    },
  })

  const verifications = Array.isArray(verificationsQuery.data) ? verificationsQuery.data : []

  if (!isAuthenticated) {
    return (
      <section className="page-card card">
        <p className="eyebrow">Admin reviews</p>
        <h1>Sign in to review tutor applications.</h1>
        <div className="hero-actions">
          <Link className="primary-button" to="/sign-in">Sign in</Link>
          <Link className="secondary-button" to="/join">Create account</Link>
        </div>
      </section>
    )
  }

  if (user?.role !== 'ADMIN') {
    return (
      <section className="page-card card">
        <p className="eyebrow">Admin reviews</p>
        <h1>This area is for admins only.</h1>
        <div className="hero-actions">
          <Link className="primary-button" to="/tutors">Browse tutors</Link>
          <Link className="secondary-button" to="/contact">Contact support</Link>
        </div>
      </section>
    )
  }

  return (
    <>
      <section className="page-card card">
        <p className="eyebrow">Admin reviews</p>
        <h1>Review tutor verification requests.</h1>
        <p className="supporting-text">Approve tutors only after documents, agreement, and subject coverage are complete.</p>
        {notice ? <p className="supporting-text">{notice}</p> : null}
      </section>

      <section className="card trust-section">
        <div className="section-heading section-heading-center">
          <div>
            <p className="eyebrow">Pending</p>
            <h2>{verificationsQuery.isLoading ? 'Loading tutor requests...' : `${verifications.length} pending request${verifications.length === 1 ? '' : 's'}`}</h2>
          </div>
          <p className="section-text section-text-center">Each review is document-backed and controlled by admin approval.</p>
        </div>
      </section>

      <section className="cards-grid">
        {verificationsQuery.isLoading ? (
          Array.from({ length: 3 }).map((_, index) => (
            <article className="tutor-card tutor-card-skeleton" key={index} aria-busy="true">
              <div className="skeleton skeleton-line skeleton-title" />
              <div className="skeleton skeleton-line" />
              <div className="skeleton skeleton-line" />
              <div className="skeleton skeleton-line skeleton-button" />
            </article>
          ))
        ) : verifications.length === 0 ? (
          <article className="panel card">
            <p className="supporting-text">No pending tutor verifications right now.</p>
          </article>
        ) : (
          verifications.map((verification) => {
            const docs = Array.isArray(verification.documents) ? verification.documents : []
            const missing = Array.isArray(verification.missing_required_documents) ? verification.missing_required_documents : []
            const reason = reasonById[verification.id] || ''

            return (
              <article className="tutor-card" key={verification.id}>
                <div className="tutor-card-top">
                  <div>
                    <h3>{verification.tutor_name || verification.tutor_email}</h3>
                    <p>{verification.tutor_email}</p>
                  </div>
                  <span className="soft-chip">{verification.status}</span>
                </div>
                <div className="trust-marks" style={{ marginBottom: '1rem' }}>
                  {missing.length > 0 ? missing.map((item) => (
                    <span className="trust-mark" key={item}>{item}</span>
                  )) : <span className="trust-mark">All required docs uploaded</span>}
                </div>
                <div className="mini-list">
                  {docs.map((doc) => (
                    <div key={doc.id}>
                      <span>{doc.doc_type_display || doc.doc_type}</span>
                      <small>
                        <a href={doc.file} target="_blank" rel="noreferrer">Open file</a>
                      </small>
                    </div>
                  ))}
                </div>
                <textarea
                  rows="3"
                  placeholder="Reason or review note"
                  value={reason}
                  onChange={(event) => setReasonById((current) => ({ ...current, [verification.id]: event.target.value }))}
                  style={{ marginTop: '1rem' }}
                />
                <div className="hero-actions" style={{ marginTop: '1rem' }}>
                  <button
                    className="primary-button"
                    type="button"
                    onClick={() => decisionMutation.mutate({ id: verification.id, status: 'APPROVED', reason })}
                    disabled={decisionMutation.isPending}
                  >
                    Approve
                  </button>
                  <button
                    className="secondary-button"
                    type="button"
                    onClick={() => decisionMutation.mutate({ id: verification.id, status: 'REJECTED', reason })}
                    disabled={decisionMutation.isPending}
                  >
                    Reject
                  </button>
                </div>
              </article>
            )
          })
        )}
      </section>
    </>
  )
}

export function AdminDisputesPage() {
  const { user, isAuthenticated } = useAuth()
  const queryClient = useQueryClient()
  const [commentById, setCommentById] = useState({})
  const [notice, setNotice] = useState('')

  const disputesQuery = useQuery({
    queryKey: ['admin-disputes'],
    queryFn: async () => (await listDisputes()).data,
    enabled: isAuthenticated && user?.role === 'ADMIN',
  })

  const decisionMutation = useMutation({
    mutationFn: async ({ id, status, comment }) => (await decideDispute(id, { status, comment })).data,
    onSuccess: async () => {
      setNotice('Dispute updated successfully.')
      await queryClient.invalidateQueries({ queryKey: ['admin-disputes'] })
    },
  })

  const disputes = Array.isArray(disputesQuery.data) ? disputesQuery.data : []

  if (!isAuthenticated) {
    return (
      <section className="page-card card">
        <p className="eyebrow">Admin disputes</p>
        <h1>Sign in to review disputes.</h1>
        <div className="hero-actions">
          <Link className="primary-button" to="/sign-in">Sign in</Link>
          <Link className="secondary-button" to="/join">Create account</Link>
        </div>
      </section>
    )
  }

  if (user?.role !== 'ADMIN') {
    return (
      <section className="page-card card">
        <p className="eyebrow">Admin disputes</p>
        <h1>This area is for admins only.</h1>
        <div className="hero-actions">
          <Link className="primary-button" to="/bookings">View bookings</Link>
          <Link className="secondary-button" to="/contact">Contact support</Link>
        </div>
      </section>
    )
  }

  return (
    <>
      <section className="page-card card">
        <p className="eyebrow">Admin disputes</p>
        <h1>Review booking disputes.</h1>
        <p className="supporting-text">Handle reported bookings and keep the marketplace trusted.</p>
        {notice ? <p className="supporting-text">{notice}</p> : null}
      </section>

      <section className="card trust-section">
        <div className="section-heading section-heading-center">
          <div>
            <p className="eyebrow">Open cases</p>
            <h2>{disputesQuery.isLoading ? 'Loading disputes...' : `${disputes.length} dispute${disputes.length === 1 ? '' : 's'}`}</h2>
          </div>
          <p className="section-text section-text-center">Each case includes the report reason and current status.</p>
        </div>
      </section>

      <section className="cards-grid">
        {disputesQuery.isLoading ? (
          Array.from({ length: 3 }).map((_, index) => (
            <article className="tutor-card tutor-card-skeleton" key={index} aria-busy="true">
              <div className="skeleton skeleton-line skeleton-title" />
              <div className="skeleton skeleton-line" />
              <div className="skeleton skeleton-line" />
              <div className="skeleton skeleton-line skeleton-button" />
            </article>
          ))
        ) : disputes.length === 0 ? (
          <article className="panel card">
            <p className="supporting-text">No disputes found.</p>
          </article>
        ) : (
          disputes.map((dispute) => {
            const comment = commentById[dispute.id] || ''
            return (
              <article className="tutor-card" key={dispute.id}>
                <div className="tutor-card-top">
                  <div>
                    <h3>Booking #{dispute.booking_id}</h3>
                    <p>{dispute.reported_by_email} reported {dispute.reported_against_email}</p>
                  </div>
                  <span className="soft-chip">{dispute.status}</span>
                </div>
                <p className="tutor-price">{dispute.reason}</p>
                <div className="mini-list">
                  <div><span>Admin note: {dispute.admin_comment || 'None'}</span></div>
                  <div><span>Resolved: {dispute.resolved_at || 'No'}</span></div>
                </div>
                <textarea
                  rows="3"
                  placeholder="Admin comment"
                  value={comment}
                  onChange={(event) => setCommentById((current) => ({ ...current, [dispute.id]: event.target.value }))}
                  style={{ marginTop: '1rem' }}
                />
                <div className="hero-actions" style={{ marginTop: '1rem' }}>
                  <button
                    className="primary-button"
                    type="button"
                    onClick={() => decisionMutation.mutate({ id: dispute.id, status: 'RESOLVED', comment })}
                    disabled={decisionMutation.isPending}
                  >
                    Resolve
                  </button>
                  <button
                    className="secondary-button"
                    type="button"
                    onClick={() => decisionMutation.mutate({ id: dispute.id, status: 'REJECTED', comment })}
                    disabled={decisionMutation.isPending}
                  >
                    Reject
                  </button>
                  <button
                    className="secondary-button"
                    type="button"
                    onClick={() => decisionMutation.mutate({ id: dispute.id, status: 'UNDER_REVIEW', comment })}
                    disabled={decisionMutation.isPending}
                  >
                    Mark review
                  </button>
                </div>
              </article>
            )
          })
        )}
      </section>
    </>
  )
}

